#include <bits/stdc++.h>
using namespace std;
const int INF=1e8;
int n,m,k,s[21][21],dp[21][21][21][21];
bool b[21][21][21][21];
int sum(int x,int y,int u,int v){
	return s[u][v]-s[x-1][v]-s[u][y-1]+s[x-1][y-1];
}
int dfs(int i,int j,int l,int r){
	if(b[i][j][l][r])
		return dp[i][j][l][r];
	b[i][j][l][r]=1;
	if(sum(i,j,l,r)==1){
		dp[i][j][l][r]=0;
		return 0;
	}
	if(sum(i,j,l,r)==0){
		dp[i][j][l][r]=INF;
		return INF;
	}
	dp[i][j][l][r]=INF;
	for(int h=i+1;h<=l;h++)
		dp[i][j][l][r]=min(dp[i][j][l][r],dfs(i,j,h-1,r)+dfs(h,j,l,r)+(r-j+1));
	for(int z=j+1;z<=r;z++)
		dp[i][j][l][r]=min(dp[i][j][l][r],dfs(i,j,l,z-1)+dfs(i,z,l,r)+(l-i+1));
	return dp[i][j][l][r];
}
int main(){
	scanf("%d%d%d",&n,&m,&k);
	for(int i=1;i<=k;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		s[u][v]=1;
	}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			s[i][j]+=s[i-1][j]+s[i][j-1]-s[i-1][j-1];
	printf("%d",dfs(1,1,n,m));
	return 0;
}
